import{_ as c,u as e,c as s,f as t,a as i,o}from"./B30Tc1zV.js";const n={class:"legal-page"},l={__name:"privacy-policy",setup(r){e({title:"Privacy Policy | Pica Caravan",meta:[{name:"description",content:"Informativa sulla privacy di Pica Caravan. Scopri come trattiamo i tuoi dati personali in conformità al GDPR."}]});const d=()=>{window.silktideCookieBannerManager&&window.silktideCookieBannerManager.toggleModal(!0)};return(v,a)=>(o(),s("div",n,[a[7]||(a[7]=t('<div class="legal-hero" data-v-c8fbc8d8><div class="container" data-v-c8fbc8d8><span class="legal-badge" data-v-c8fbc8d8>Trasparenza &amp; Sicurezza</span><h1 class="legal-title" data-v-c8fbc8d8>Privacy Policy</h1><p class="legal-subtitle" data-v-c8fbc8d8>Informativa sul trattamento dei dati personali ai sensi del GDPR.</p></div><div class="hero-glow" data-v-c8fbc8d8></div></div>',1)),i("div",{class:"container legal-container"},[i("div",{class:"legal-layout"},[a[6]||(a[6]=t('<aside class="legal-sidebar" data-v-c8fbc8d8><div class="index-card" data-v-c8fbc8d8><h3 data-v-c8fbc8d8>Indice</h3><ul data-v-c8fbc8d8><li data-v-c8fbc8d8><a href="#titolare" data-v-c8fbc8d8>1. Titolare</a></li><li data-v-c8fbc8d8><a href="#dati" data-v-c8fbc8d8>2. Dati Raccolti</a></li><li data-v-c8fbc8d8><a href="#finalita" data-v-c8fbc8d8>3. Finalità</a></li><li data-v-c8fbc8d8><a href="#basi" data-v-c8fbc8d8>4. Trasferimenti</a></li><li data-v-c8fbc8d8><a href="#conservazione" data-v-c8fbc8d8>5. Conservazione</a></li><li data-v-c8fbc8d8><a href="#diritti" data-v-c8fbc8d8>6. I tuoi Diritti</a></li></ul></div></aside>',1)),i("main",{class:"legal-content"},[a[5]||(a[5]=t('<div class="update-info" data-v-c8fbc8d8><span data-v-c8fbc8d8>Ultimo aggiornamento: 22 Marzo 2026</span></div><section id="titolare" class="legal-section" data-v-c8fbc8d8><div class="section-number" data-v-c8fbc8d8>01</div><h2 data-v-c8fbc8d8>Titolare del Trattamento</h2><div class="section-body" data-v-c8fbc8d8><p data-v-c8fbc8d8>Il Titolare del Trattamento dei dati è <strong data-v-c8fbc8d8>ROAD RUNNER DI TARTAGLIONE PASQUALE</strong>, con sede legale in VIA SAN FRANCESCO 13 - 81020 - CAPODRISE (CE). P.IVA: 04335610616. Email: <a href="mailto:inforoadrunner@libero.it" data-v-c8fbc8d8>inforoadrunner@libero.it</a>.</p></div></section><section id="dati" class="legal-section" data-v-c8fbc8d8><div class="section-number" data-v-c8fbc8d8>02</div><h2 data-v-c8fbc8d8>Tipologia di dati raccolti</h2><div class="section-body" data-v-c8fbc8d8><p data-v-c8fbc8d8>Attraverso questo sito web raccogliamo i seguenti dati personali:</p><div class="data-grid" data-v-c8fbc8d8><div class="data-item" data-v-c8fbc8d8><strong data-v-c8fbc8d8>Dati identificativi</strong><p data-v-c8fbc8d8>Nome, Cognome, Indirizzo (per valutazioni permuta).</p></div><div class="data-item" data-v-c8fbc8d8><strong data-v-c8fbc8d8>Dati di contatto</strong><p data-v-c8fbc8d8>Email, numero di telefono (WhatsApp incluso).</p></div><div class="data-item" data-v-c8fbc8d8><strong data-v-c8fbc8d8>Dati del veicolo</strong><p data-v-c8fbc8d8>Marca, modello, anno, km, condizioni e immagini.</p></div><div class="data-item" data-v-c8fbc8d8><strong data-v-c8fbc8d8>Dati di navigazione</strong><p data-v-c8fbc8d8>Indirizzo IP, tipo di browser, dati di log anonimizzati.</p></div></div></div></section><section id="finalita" class="legal-section" data-v-c8fbc8d8><div class="section-number" data-v-c8fbc8d8>03</div><h2 data-v-c8fbc8d8>Finalità e Basi Giuridiche</h2><div class="section-body" data-v-c8fbc8d8><p data-v-c8fbc8d8>I dati vengono trattati per le seguenti finalità, basate su specifiche basi giuridiche:</p><ul class="feature-list" data-v-c8fbc8d8><li data-v-c8fbc8d8><strong data-v-c8fbc8d8>Gestione Richieste &amp; Preventivi:</strong> Esecuzione di misure precontrattuali su richiesta dell&#39;interessato.</li><li data-v-c8fbc8d8><strong data-v-c8fbc8d8>Valutazione Permuta:</strong> Necessaria per la formulazione di un&#39;offerta commerciale tecnica.</li><li data-v-c8fbc8d8><strong data-v-c8fbc8d8>Assistenza WhatsApp:</strong> Il contatto tramite WhatsApp (Meta Platforms, Inc.) avviene su iniziativa dell&#39;utente. I dati sono trattati per fornire il supporto richiesto.</li><li data-v-c8fbc8d8><strong data-v-c8fbc8d8>Obblighi Fiscali:</strong> Adempimento di obblighi di legge (es. fatturazione, registri vendita veicoli).</li><li data-v-c8fbc8d8><strong data-v-c8fbc8d8>Analisi Statistica:</strong> Legittimo interesse del titolare (tramite cookie tecnici o analitici anonimizzati).</li></ul></div></section><section id="basi" class="legal-section" data-v-c8fbc8d8><div class="section-number" data-v-c8fbc8d8>04</div><h2 data-v-c8fbc8d8>Trasferimenti extra-UE</h2><div class="section-body" data-v-c8fbc8d8><p data-v-c8fbc8d8>Per l&#39;erogazione di alcuni servizi (es. Google Analytics, Google Maps, WhatsApp), i dati potrebbero essere trasferiti verso server situati negli Stati Uniti.</p><div class="info-box" data-v-c8fbc8d8><p data-v-c8fbc8d8>Tali trasferimenti sono garantiti dall&#39;adesione dei fornitori al <strong data-v-c8fbc8d8>Data Privacy Framework (DPF)</strong> o dalla sottoscrizione di <strong data-v-c8fbc8d8>Clausole Contrattuali Standard (SCC)</strong> approvate dalla Commissione Europea.</p></div></div></section><section id="conservazione" class="legal-section" data-v-c8fbc8d8><div class="section-number" data-v-c8fbc8d8>05</div><h2 data-v-c8fbc8d8>Tempi di conservazione</h2><div class="section-body" data-v-c8fbc8d8><p data-v-c8fbc8d8>I dati personali saranno conservati secondo i seguenti criteri:</p><ul class="feature-list" data-v-c8fbc8d8><li data-v-c8fbc8d8><strong data-v-c8fbc8d8>Dati di contatto/richieste:</strong> fino a 24 mesi dalla conclusione della gestione della richiesta, salvo instaurazione di un rapporto contrattuale.</li><li data-v-c8fbc8d8><strong data-v-c8fbc8d8>Dati fiscali/contrattuali:</strong> per 10 anni come previsto dalla normativa civile e fiscale italiana.</li><li data-v-c8fbc8d8><strong data-v-c8fbc8d8>Dati di navigazione:</strong> rimossi entro 12 mesi, salvo necessità di accertamento di reati.</li></ul></div></section>',6)),i("section",{id:"diritti",class:"legal-section"},[a[3]||(a[3]=i("div",{class:"section-number"},"06",-1)),a[4]||(a[4]=i("h2",null,"I tuoi Diritti",-1)),i("div",{class:"section-body"},[a[2]||(a[2]=i("p",null,"Ai sensi del GDPR, hai il diritto di accedere, rettificare, cancellare o limitare il trattamento dei tuoi dati.",-1)),i("div",{class:"legal-actions"},[a[1]||(a[1]=i("div",{class:"contact-card"},[i("p",null,"Per esercitare tali diritti, scrivi a:"),i("a",{href:"mailto:inforoadrunner@libero.it",class:"btn-email"},"inforoadrunner@libero.it")],-1)),i("div",{class:"consent-card"},[a[0]||(a[0]=i("p",null,"Vuoi modificare le tue preferenze sui cookie?",-1)),i("button",{onClick:d,class:"btn-consent"},"Gestisci Consenso")])])])])])])])]))}},b=c(l,[["__scopeId","data-v-c8fbc8d8"]]);export{b as default};
